 1	import * as _ from 'lodash';
 2	import * as React from 'react';
 3	import { useTranslation } from 'react-i18next';
 4	import { useDispatch } from 'react-redux';
 5	import { useLocation, useNavigate } from 'react-router-dom-v5-compat';
 6	import { useActiveNamespace } from '@openshift-console/dynamic-plugin-sdk';
 7	import { Button, ButtonVariant, Tooltip } from '@patternfly/react-core';
 8	import { PlusCircleIcon } from '@patternfly/react-icons';
 9	
10	import { closeOLS, importCodeBlock } from '../redux-actions';
11	import ConfirmationModal from './ConfirmationModal';
12	
13	type Props = {
14	  value: string;
15	};
16	
17	const ALL_NAMESPACES_KEY = '#ALL_NS#';
18	
19	const ImportAction: React.FC<Props> = ({ value }) => {
20	  const { t } = useTranslation('plugin__lightspeed-console-plugin');
21	  const location = useLocation();
22	  const dispatch = useDispatch();
23	  const navigate = useNavigate();
24	  const [activeNamespace] = useActiveNamespace();
25	
26	  const isImportYAMLPage = location?.pathname?.split('/').pop() === 'import';
27	
28	  const [showModal, setShowModal] = React.useState(false);
29	
30	  // The web console only supports the import YAML action from version 4.18
31	  const { releaseVersion } = window.SERVER_FLAGS;
32	  if (releaseVersion) {
33	    const [major, minor] = releaseVersion.split('.');
34	    if (Number(major) < 4 || (Number(major) === 4 && Number(minor) < 18)) {
35	      return null;
36	    }
37	  }
38	
39	  const handleRedirect = (event: React.MouseEvent<HTMLButtonElement>) => {
40	    if (event.currentTarget.id === 'leave') {
41	      navigate(
42	        activeNamespace === ALL_NAMESPACES_KEY
43	          ? `/k8s/all-namespaces/import?ols=true`
44	          : `/k8s/ns/${activeNamespace}/import?ols=true`,
45	      );
46	      dispatch(closeOLS());
47	    }
48	    setShowModal(false);
49	  };
50	
51	  const handleClick = () => {
52	    if (isImportYAMLPage) {
53	      navigate(`${location.pathname}?ols=true`, { replace: true });
54	    } else {
55	      setShowModal(true);
56	    }
57	    dispatch(
58	      // Ensure the object triggers updates, even with the same value
59	      importCodeBlock({
60	        value,
61	        id: _.uniqueId('ImportCodeBlock_'),
62	        triggeredFrom: location?.pathname,
63	      }),
64	    );
65	  };
66	
67	  return (
68	    <>
69	      {showModal && !isImportYAMLPage && <ConfirmationModal handleRedirect={handleRedirect} />}
70	      <Tooltip aria="none" content={t('Import to console')} trigger="mouseenter focus click">
71	        <Button
72	          aria-label={t('Import to console')}
73	          onClick={handleClick}
74	          variant={ButtonVariant.plain}
75	        >
76	          <PlusCircleIcon />
77	        </Button>
78	      </Tooltip>
79	    </>
80	  );
81	};
82	
83	export default ImportAction;

